/**
 * Tests for CC 2.1.77 PreToolUse allow/deny fix compliance.
 *
 * Verifies that advisory dispatchers use outputWithContext (no permission decision)
 * instead of outputAllowWithContext (declares permissionDecision: 'allow').
 *
 * CC 2.1.77 changed behavior: "allow" from hooks no longer bypasses deny rules.
 * Advisory hooks should never declare a permission decision — they only inject context.
 */

import { describe, test, expect, vi } from 'vitest';

// Mock hook dependencies to isolate dispatcher logic
vi.mock('../../pretool/Write/security-pattern-validator.js', () => ({
  securityPatternValidator: () => ({ continue: true, suppressOutput: true }),
}));
vi.mock('../../pretool/Write/architecture-change-detector.js', () => ({
  architectureChangeDetector: () => ({
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: {
      hookEventName: 'PostToolUse',
      additionalContext: 'Architecture: test context',
    },
  }),
}));
vi.mock('../../pretool/bash/error-pattern-warner.js', () => ({
  errorPatternWarner: () => ({ continue: true, suppressOutput: true }),
}));
vi.mock('../../pretool/bash/gh-issue-creation-guide.js', () => ({
  ghIssueCreationGuide: () => ({ continue: true, suppressOutput: true }),
}));
vi.mock('../../pretool/bash/affected-tests-finder.js', () => ({
  affectedTestsFinder: () => ({ continue: true, suppressOutput: true }),
}));
vi.mock('../../pretool/task/task-agent-advisor.js', () => ({
  taskAgentAdvisor: () => ({ continue: true, suppressOutput: true }),
}));

import { readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

// Import dispatchers under test
import { unifiedWriteEditQualityDispatcher } from '../../pretool/write-edit/unified-quality-dispatcher.js';

const __dirname = dirname(fileURLToPath(import.meta.url));
const SRC_ROOT = resolve(__dirname, '../..');

const makeInput = (tool: string, command?: string) => ({
  tool_name: tool,
  tool_input: command ? { command } : { file_path: '/test/file.ts', content: 'test' },
  session_id: 'test-session',
});

describe('advisory-dispatcher-output (CC 2.1.77 compliance)', () => {
  describe('unified-quality-dispatcher', () => {
    test('returns outputWithContext, not outputAllowWithContext', () => {
      const result = unifiedWriteEditQualityDispatcher(makeInput('Write') as any);

      // Should have continue: true
      expect(result.continue).toBe(true);

      // Should NOT have permissionDecision (that's the old buggy pattern)
      if (result.hookSpecificOutput) {
        expect(result.hookSpecificOutput).not.toHaveProperty('permissionDecision');
      }
    });

    test('silent success when no context produced has no permissionDecision', () => {
      // Mock architecture detector to return no context
      vi.doMock('../../pretool/Write/architecture-change-detector.js', () => ({
        architectureChangeDetector: () => ({ continue: true, suppressOutput: true }),
      }));

      const result = unifiedWriteEditQualityDispatcher(makeInput('Write') as any);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      if (result.hookSpecificOutput) {
        expect(result.hookSpecificOutput).not.toHaveProperty('permissionDecision');
      }
    });
  });

  describe('static regression: no outputAllowWithContext in advisory dispatchers', () => {
    // These 3 dispatchers are advisory-only and must NOT use outputAllowWithContext.
    // CC 2.1.77 fixed "allow" bypassing deny — advisory hooks should use outputWithContext.
    const ADVISORY_DISPATCHERS = [
      'pretool/write-edit/unified-quality-dispatcher.ts',
      'pretool/bash/unified-advisory-dispatcher.ts',
      'pretool/task/unified-agent-safety-dispatcher.ts',
    ];

    test.each(ADVISORY_DISPATCHERS)('%s does not import outputAllowWithContext', (file) => {
      const content = readFileSync(resolve(SRC_ROOT, file), 'utf-8');
      expect(content).not.toContain('outputAllowWithContext');
    });

    test.each(ADVISORY_DISPATCHERS)('%s uses outputWithContext instead', (file) => {
      const content = readFileSync(resolve(SRC_ROOT, file), 'utf-8');
      expect(content).toContain('outputWithContext');
    });
  });
});
